<div class="module-page form-grid"><section class="glass-card form-card"><h3>Crear incidencia</h3><form class="stack-form" method="POST" action="<?= e(page_url('encargado-incidencias')) ?>"><?= csrf_field() ?><select name="idAlberca" class="form-select"><?php foreach($p as $pool): ?><option value="<?= e($pool['idAlberca']) ?>"><?= e($pool['nombre']) ?></option><?php endforeach; ?></select><select name="idTipoIncidencia" class="form-select"><?php foreach($cats['tipos'] as $x): ?><option value="<?= e($x['idTipoIncidencia']) ?>"><?= e($x['nombre']) ?></option><?php endforeach; ?></select><select name="idPrioridad" class="form-select"><?php foreach($cats['prioridades'] as $x): ?><option value="<?= e($x['idPrioridad']) ?>"><?= e($x['nombre']) ?></option><?php endforeach; ?></select><textarea class="form-control" name="descripcion" required placeholder="Descripción"></textarea><button class="btn btn-aqua">Enviar a FIFO</button></form></section><section class="glass-card"><h3>Cola FIFO</h3><div class="ticket-list"><?php foreach($tickets as $x): ?><div class="ticket-item"><b><?= e($x['folio']) ?> · <?= e($x['prioridad']) ?></b><span><?= e($x['alberca']) ?> · <?= e($x['estado']) ?></span><small><?= e($x['descripcion']) ?></small></div><?php endforeach; ?></div></section></div>
